SELECT COUNT(*) AS session_count
FROM sessions
WHERE house_id = (SELECT house_id FROM houses WHERE house_name = 'Upper House');

SELECT house_name
FROM houses
WHERE house_id = 1;

SELECT speaker_name
FROM speakers
WHERE speaker_id IN (SELECT speaker_id FROM speeches);

SELECT speaker_name
FROM speakers
ORDER BY speaker_name;

SELECT party_name
FROM parties
WHERE party_id IN (
  SELECT DISTINCT party_id
  FROM speaker_party_affiliations
);

SELECT speaker_name, speaker_gender
FROM speakers
ORDER BY speaker_gender;
